#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *deg = (int*)calloc(N+1, sizeof(int));
        for(int i=0;i<N-1;i++){
            int u,v; scanf("%d %d", &u, &v);
            deg[u]++; deg[v]++;
        }
        int leaf=0;
        for(int i=1;i<=N;i++) if(deg[i]==1) leaf++;
        int ans = (leaf + 1)/2 - 1;
        if(ans<0) ans=0;
        printf("%d\n", ans);
        free(deg);
    }
    return 0;
}

