let idx = 0;
const T = input[idx++];
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const deg = new Array(N + 1).fill(0);
  for (let i = 0; i < N - 1; i++) {
    const u = input[idx++];
    const v = input[idx++];
    deg[u]++; deg[v]++;
  }
  let leaf = 0;
  for (let i = 1; i <= N; i++) if (deg[i] === 1) leaf++;
  let ans = Math.floor((leaf + 1) / 2) - 1;
  if (ans < 0) ans = 0;
  outputs.push(String(ans));
}
